class Solution:
    def findWinningPlayer(self, skills: List[int], k: int) -> int:
        max_skill = skills[0]
        current_winner = 0
        consecutive_wins = 0

        for i in range(1, len(skills)):
            if skills[i] > max_skill:
                max_skill = skills[i]
                current_winner = i
                consecutive_wins = 1
            else:
                consecutive_wins += 1

            if consecutive_wins == k:
                return current_winner

        return current_winner
